import React, { useState, useEffect } from 'react';
import {
    Container,
    Grid,
    Paper,
    Typography,
    Box,
    Card,
    CardContent,
    Button,
    ButtonGroup,
    Table,
    TableBody,
    TableCell,
    TableContainer,
    TableHead,
    TableRow,
    Tabs,
    Tab,
    Menu,
    MenuItem,
    Dialog,
    DialogTitle,
    DialogContent,
    DialogActions,
} from '@mui/material';
import { useNavigate } from 'react-router-dom';
import { statsAPI, activitiesAPI, workoutsAPI } from '../services/api';
import Activities from './Activities';
import Goals from './Goals';
import Steps from './Steps';
import Calendar from './Calendar';
import { Line, Doughnut } from 'react-chartjs-2';
import {
    Chart as ChartJS,
    CategoryScale,
    LinearScale,
    PointElement,
    LineElement,
    ArcElement,
    Title,
    Tooltip,
    Legend,
} from 'chart.js';

ChartJS.register(
    CategoryScale,
    LinearScale,
    PointElement,
    LineElement,
    ArcElement,
    Title,
    Tooltip,
    Legend
);

const Dashboard = () => {
    const [stats, setStats] = useState(null);
    const [summary, setSummary] = useState({});
    const [recentActivities, setRecentActivities] = useState([]);
    const [activitiesFull, setActivitiesFull] = useState([]);
    const [upcomingWorkouts, setUpcomingWorkouts] = useState([]);
    const [selectedPeriod, setSelectedPeriod] = useState('week');
    const [tabValue, setTabValue] = useState(0);
    const [recentAnchor, setRecentAnchor] = useState(null);
    const [recentDialogOpen, setRecentDialogOpen] = useState(false);
    const [selectedRecentActivity, setSelectedRecentActivity] = useState(null);
    const navigate = useNavigate();

    useEffect(() => {
        fetchDashboardData();
    }, [selectedPeriod]);

    const fetchDashboardData = async () => {
        try {
            const [statsRes, summaryRes, activitiesRes, upcomingRes] = await Promise.all([
                statsAPI.getStats(),
                activitiesAPI.getSummary(),
                activitiesAPI.getActivities(),
                workoutsAPI.getUpcomingWorkouts(),
            ]);

            setStats(statsRes.data);
            setSummary(summaryRes.data);
            setRecentActivities(activitiesRes.data.slice(0, 5));
            setActivitiesFull(activitiesRes.data || []);
            setUpcomingWorkouts(upcomingRes.data || []);
        } catch (error) {
            console.error('Error fetching dashboard data:', error);
        }
    };

    const handleTabChange = (event, newValue) => {
        setTabValue(newValue);
    };

    const lineChartData = {
        labels: Object.keys(summary).slice(-7),
        datasets: [
            {
                label: 'Calories Burned',
                data: Object.values(summary).slice(-7).map(day => day.total_calories),
                borderColor: 'rgb(75, 192, 192)',
                tension: 0.1,
            },
        ],
    };

    const doughnutData = stats ? {
        labels: Object.keys(stats.activity_distribution),
        datasets: [
            {
                data: Object.values(stats.activity_distribution),
                backgroundColor: [
                    'rgba(255, 99, 132, 0.8)',
                    'rgba(54, 162, 235, 0.8)',
                    'rgba(255, 206, 86, 0.8)',
                    'rgba(75, 192, 192, 0.8)',
                    'rgba(153, 102, 255, 0.8)',
                ],
            },
        ],
    } : null;

    return (
        <Container maxWidth="xl" className="dashboard-container">
            {/* Navigation Tabs */}
            <Paper className="tabs-paper">
                <Tabs 
                    value={tabValue} 
                    onChange={handleTabChange}
                    indicatorColor="primary"
                    textColor="primary"
                    variant="scrollable"
                    scrollButtons="auto"
                >
                    <Tab label="📊 Overview" />
                    <Tab label="🏃 Activities" />
                    <Tab label="🎯 Goals" />
                    <Tab label="👟 Steps" />
                    <Tab label="📅 Calendar & Schedule" />
                </Tabs>
            </Paper>

            {/* Tab Content */}
            {tabValue === 0 && (
            <>
            <Box className="dashboard-header">
                <Typography variant="h4">
                    📊 Fitness Dashboard
                </Typography>
                <ButtonGroup variant="outlined" size="small">
                    <Button 
                        onClick={() => setSelectedPeriod('week')}
                        variant={selectedPeriod === 'week' ? 'contained' : 'outlined'}
                    >
                        This Week
                    </Button>
                    <Button 
                        onClick={() => setSelectedPeriod('last-week')}
                        variant={selectedPeriod === 'last-week' ? 'contained' : 'outlined'}
                    >
                        Last Week
                    </Button>
                    <Button 
                        onClick={() => setSelectedPeriod('month')}
                        variant={selectedPeriod === 'month' ? 'contained' : 'outlined'}
                    >
                        This Month
                    </Button>
                    <Button 
                        onClick={() => setSelectedPeriod('last-month')}
                        variant={selectedPeriod === 'last-month' ? 'contained' : 'outlined'}
                    >
                        Last Month
                    </Button>
                </ButtonGroup>
            </Box>

            <Grid container spacing={3}>
                {/* Upcoming Workouts - FIRST */}
                <Grid item xs={12} md={6}>
                    <Paper className="paper-p2">
                        <Typography variant="h6" gutterBottom>
                            📅 Upcoming Workouts
                        </Typography>
                        {upcomingWorkouts.length > 0 ? (
                            <TableContainer>
                                <Table size="small">
                                    <TableHead>
                                        <TableRow className="table-header-row">
                                            <TableCell className="table-header-cell">Activity</TableCell>
                                            <TableCell className="table-header-cell">Date & Time</TableCell>
                                            <TableCell className="table-header-cell">Duration</TableCell>
                                        </TableRow>
                                    </TableHead>
                                    <TableBody>
                                        {upcomingWorkouts.map((workout) => (
                                            <TableRow key={workout.id}>
                                                <TableCell>{workout.activity_type}</TableCell>
                                                <TableCell>
                                                    {new Date(workout.scheduled_date).toLocaleDateString()} {' '}
                                                    {workout.scheduled_time}
                                                </TableCell>
                                                <TableCell>{workout.duration} min</TableCell>
                                            </TableRow>
                                        ))}
                                    </TableBody>
                                </Table>
                            </TableContainer>
                        ) : (
                            <Typography variant="body2" color="textSecondary" className="no-activities">
                                No upcoming workouts scheduled. Plan one in the Calendar!
                            </Typography>
                        )}
                    </Paper>
                </Grid>

                {/* Stats Cards */}
                <Grid item xs={12} md={3}>
                    <Card>
                        <CardContent>
                            <Typography color="textSecondary" gutterBottom>
                                Weekly Workouts
                            </Typography>
                            <Typography variant="h5">
                                {stats?.weekly_stats?.activity_count || 0}
                            </Typography>
                        </CardContent>
                    </Card>
                </Grid>

                <Grid item xs={12} md={3}>
                    <Card>
                        <CardContent>
                            <Typography color="textSecondary" gutterBottom>
                                Total Duration
                            </Typography>
                            <Typography variant="h5">
                                {stats?.weekly_stats?.total_duration || 0} min
                            </Typography>
                        </CardContent>
                    </Card>
                </Grid>

                <Grid item xs={12} md={3}>
                    <Card>
                        <CardContent>
                            <Typography color="textSecondary" gutterBottom>
                                Calories Burned
                            </Typography>
                            <Typography variant="h5">
                                {stats?.weekly_stats?.total_calories?.toFixed(0) || 0}
                            </Typography>
                        </CardContent>
                    </Card>
                </Grid>

                <Grid item xs={12} md={3}>
                    <Card>
                        <CardContent>
                            <Typography color="textSecondary" gutterBottom>
                                Total Distance
                            </Typography>
                            <Typography variant="h5">
                                {stats?.weekly_stats?.total_distance?.toFixed(1) || 0} km
                            </Typography>
                        </CardContent>
                    </Card>
                </Grid>

                {/* Charts */}
                <Grid item xs={12} md={8}>
                    <Paper className="paper-p2">
                        <Typography variant="h6" gutterBottom>
                            7-Day Progress
                        </Typography>
                        <Line data={lineChartData} />
                    </Paper>
                </Grid>

                <Grid item xs={12} md={4}>
                    <Paper className="paper-p2">
                        <Typography variant="h6" gutterBottom>
                            Activity Distribution
                        </Typography>
                        {doughnutData && <Doughnut data={doughnutData} />}
                    </Paper>
                </Grid>

                {/* Activity Form */}
{/* Activity Form removed - moved to Activities page */}

                {/* Recent Activities (dropdown + dialog) */}
                <Grid item xs={12} md={6}>
                    <Paper className="paper-p2">
                        <Typography variant="h6" gutterBottom>
                            🏃 Recent Activities
                        </Typography>

                        <Box sx={{ mt: 2 }}>
                            <Button variant="outlined" onClick={(e) => setRecentAnchor(e.currentTarget)}>
                                Open Recent
                            </Button>
                            <Menu
                                anchorEl={recentAnchor}
                                open={Boolean(recentAnchor)}
                                onClose={() => setRecentAnchor(null)}
                            >
                                {recentActivities.length === 0 && (
                                    <MenuItem disabled>No recent activities</MenuItem>
                                )}
                                {recentActivities.map((activity) => (
                                    <MenuItem key={activity.id} onClick={() => { setRecentDialogOpen(true); setRecentAnchor(null); }}>
                                        {activity.activity_type} — {new Date(activity.date).toLocaleDateString()}
                                    </MenuItem>
                                ))}
                            </Menu>

                            <Dialog open={recentDialogOpen} onClose={() => setRecentDialogOpen(false)} maxWidth="md" fullWidth>
                                <DialogTitle sx={{ fontWeight: 'bold' }}>All Activities</DialogTitle>
                                <DialogContent>
                                    {activitiesFull && activitiesFull.length > 0 ? (
                                        <TableContainer sx={{ mt: 2 }}>
                                            <Table size="small">
                                                <TableHead>
                                                    <TableRow sx={{ backgroundColor: '#f5f5f5' }}>
                                                        <TableCell sx={{ fontWeight: 'bold' }}>Activity Type</TableCell>
                                                        <TableCell sx={{ fontWeight: 'bold' }}>Date</TableCell>
                                                        <TableCell sx={{ fontWeight: 'bold' }}>Duration (min)</TableCell>
                                                        <TableCell sx={{ fontWeight: 'bold' }}>Calories</TableCell>
                                                        <TableCell sx={{ fontWeight: 'bold' }}>Distance (km)</TableCell>
                                                    </TableRow>
                                                </TableHead>
                                                <TableBody>
                                                    {activitiesFull.map((activity) => (
                                                        <TableRow key={activity.id} hover>
                                                            <TableCell>{activity.activity_type}</TableCell>
                                                            <TableCell>{new Date(activity.date).toLocaleDateString()}</TableCell>
                                                            <TableCell>{activity.duration}</TableCell>
                                                            <TableCell>{activity.calories_burned ?? 'N/A'}</TableCell>
                                                            <TableCell>{activity.distance ?? 'N/A'}</TableCell>
                                                        </TableRow>
                                                    ))}
                                                </TableBody>
                                            </Table>
                                        </TableContainer>
                                    ) : (
                                        <Typography variant="body2" color="textSecondary" sx={{ py: 2 }}>
                                            No activities recorded yet. Start logging your workouts!
                                        </Typography>
                                    )}
                                </DialogContent>
                                <DialogActions>
                                    <Button onClick={() => setRecentDialogOpen(false)}>Close</Button>
                                </DialogActions>
                            </Dialog>
                        </Box>
                    </Paper>
                </Grid>

                {/* Upcoming Workouts */}
                <Grid item xs={12} md={6}>
                    <Paper className="paper-p2">
                        <Typography variant="h6" gutterBottom>
                            📅 Upcoming Workouts
                        </Typography>
                        {upcomingWorkouts.length > 0 ? (
                            <TableContainer>
                                <Table size="small">
                                    <TableHead>
                                        <TableRow className="table-header-row">
                                            <TableCell className="table-header-cell">Activity</TableCell>
                                            <TableCell className="table-header-cell">Date & Time</TableCell>
                                            <TableCell className="table-header-cell">Duration</TableCell>
                                        </TableRow>
                                    </TableHead>
                                    <TableBody>
                                        {upcomingWorkouts.map((workout) => (
                                            <TableRow key={workout.id}>
                                                <TableCell>{workout.activity_type}</TableCell>
                                                <TableCell>
                                                    {new Date(workout.scheduled_date).toLocaleDateString()} {' '}
                                                    {workout.scheduled_time}
                                                </TableCell>
                                                <TableCell>{workout.duration} min</TableCell>
                                            </TableRow>
                                        ))}
                                    </TableBody>
                                </Table>
                            </TableContainer>
                        ) : (
                            <Typography variant="body2" color="textSecondary" sx={{ py: 2 }}>
                                No upcoming workouts scheduled. Plan one in the Calendar!
                            </Typography>
                        )}
                    </Paper>
                </Grid>

                        {/* Activity history removed from Dashboard (kept out of profile and dashboard) */}
            </Grid>
            </>
            )}

            {/* Activities Tab */}
            {tabValue === 1 && <Activities />}

            {/* Goals Tab */}
            {tabValue === 2 && <Goals />}

            {/* Steps Tab */}
            {tabValue === 3 && <Steps />}

            {/* Calendar Tab */}
            {tabValue === 4 && <Calendar />}
        </Container>
    );
};

export default Dashboard;
